module computer_decoder_5to32 ( DECODER_in ,DECODER_out );
input	[4:0]	DECODER_in ;
output	[31:0]	DECODER_out ;
reg	[31:0]	DECODER_out ;

always @ ( DECODER_in )
	begin
	DECODER_out = 32'h00000000 ;
	DECODER_out [31 - DECODER_in] = 1'h1 ;
	end

endmodule

module computer_decoder_12to4096 ( DECODER_in ,DECODER_out );
input	[11:0]	DECODER_in ;
output	[4095:0]	DECODER_out ;
reg	[4095:0]	DECODER_out ;

always @ ( DECODER_in )
	begin
	DECODER_out = 4096' ;
	DECODER_out [4095 - DECODER_in] = 1'h1 ;
	end

endmodule
